CREATE TABLE achievements (id INTEGER PRIMARY KEY AUTOINCREMENT, user_id INTEGER NOT NULL REFERENCES users(id), title TEXT NOT NULL, description TEXT NOT NULL, awarded_at TEXT NOT NULL);

CREATE TABLE activity_logs (id INTEGER PRIMARY KEY AUTOINCREMENT, user_id INTEGER REFERENCES users(id), action TEXT NOT NULL, details TEXT NOT NULL, created_at TEXT NOT NULL);

CREATE TABLE answers (id INTEGER PRIMARY KEY AUTOINCREMENT, attempt_id INTEGER NOT NULL REFERENCES attempts(id), question_id INTEGER NOT NULL REFERENCES questions(id), option_id INTEGER NOT NULL REFERENCES options(id), is_correct INTEGER NOT NULL, created_at TEXT NOT NULL);

CREATE TABLE articles (id INTEGER PRIMARY KEY AUTOINCREMENT, title TEXT NOT NULL, slug TEXT UNIQUE NOT NULL, body TEXT NOT NULL, published_at TEXT NOT NULL);

CREATE TABLE attempts (id INTEGER PRIMARY KEY AUTOINCREMENT, user_id INTEGER NOT NULL REFERENCES users(id), scenario_id INTEGER NOT NULL REFERENCES scenarios(id), started_at TEXT NOT NULL, finished_at TEXT, score INTEGER NOT NULL DEFAULT 0, status TEXT NOT NULL DEFAULT 'started', time_spent INTEGER NOT NULL DEFAULT 0, budget_spent INTEGER NOT NULL DEFAULT 0, risk_level INTEGER NOT NULL DEFAULT 50, quality INTEGER NOT NULL DEFAULT 50, compliance INTEGER NOT NULL DEFAULT 50, ending TEXT NOT NULL DEFAULT '', final_report TEXT NOT NULL DEFAULT '');

CREATE TABLE feedback (id INTEGER PRIMARY KEY AUTOINCREMENT, name TEXT NOT NULL, email TEXT NOT NULL, topic TEXT NOT NULL, message TEXT NOT NULL, status TEXT NOT NULL DEFAULT 'new', created_at TEXT NOT NULL);

CREATE TABLE generated_documents (id INTEGER PRIMARY KEY AUTOINCREMENT, user_id INTEGER NOT NULL REFERENCES users(id), doc_type TEXT NOT NULL, title TEXT NOT NULL, file_path TEXT NOT NULL, created_at TEXT NOT NULL);

CREATE TABLE modules (id INTEGER PRIMARY KEY AUTOINCREMENT, scenario_id INTEGER NOT NULL REFERENCES scenarios(id), title TEXT NOT NULL, content TEXT NOT NULL, sort_order INTEGER NOT NULL);

CREATE TABLE options (id INTEGER PRIMARY KEY AUTOINCREMENT, question_id INTEGER NOT NULL REFERENCES questions(id), text TEXT NOT NULL, is_correct INTEGER NOT NULL DEFAULT 0);

CREATE TABLE questions (id INTEGER PRIMARY KEY AUTOINCREMENT, scenario_id INTEGER NOT NULL REFERENCES scenarios(id), text TEXT NOT NULL, explanation TEXT NOT NULL, points INTEGER NOT NULL DEFAULT 10, sort_order INTEGER NOT NULL);

CREATE TABLE roles (id INTEGER PRIMARY KEY AUTOINCREMENT, code TEXT UNIQUE NOT NULL, name TEXT NOT NULL, description TEXT NOT NULL);

CREATE TABLE scenario_choices (id INTEGER PRIMARY KEY AUTOINCREMENT, step_id INTEGER NOT NULL REFERENCES scenario_steps(id), text TEXT NOT NULL, feedback TEXT NOT NULL, next_step_code TEXT, delta_time INTEGER NOT NULL DEFAULT 0, delta_budget INTEGER NOT NULL DEFAULT 0, delta_risk INTEGER NOT NULL DEFAULT 0, delta_quality INTEGER NOT NULL DEFAULT 0, delta_compliance INTEGER NOT NULL DEFAULT 0, score INTEGER NOT NULL DEFAULT 0);

CREATE TABLE scenario_steps (id INTEGER PRIMARY KEY AUTOINCREMENT, scenario_id INTEGER NOT NULL REFERENCES scenarios(id), code TEXT NOT NULL, title TEXT NOT NULL, context TEXT NOT NULL, file_required INTEGER NOT NULL DEFAULT 0, file_instruction TEXT NOT NULL DEFAULT '', sort_order INTEGER NOT NULL, UNIQUE(scenario_id, code));

CREATE TABLE scenarios (id INTEGER PRIMARY KEY AUTOINCREMENT, title TEXT NOT NULL, slug TEXT UNIQUE NOT NULL, difficulty TEXT NOT NULL, duration_minutes INTEGER NOT NULL, summary TEXT NOT NULL, learning_goal TEXT NOT NULL, is_public INTEGER NOT NULL DEFAULT 1);

CREATE TABLE settings (id INTEGER PRIMARY KEY AUTOINCREMENT, key TEXT UNIQUE NOT NULL, value TEXT NOT NULL, description TEXT NOT NULL);

CREATE TABLE simulation_events (id INTEGER PRIMARY KEY AUTOINCREMENT, attempt_id INTEGER NOT NULL REFERENCES attempts(id), step_id INTEGER NOT NULL REFERENCES scenario_steps(id), choice_id INTEGER NOT NULL REFERENCES scenario_choices(id), uploaded_file_id INTEGER REFERENCES uploaded_files(id), time_spent INTEGER NOT NULL, budget_spent INTEGER NOT NULL, risk_level INTEGER NOT NULL, quality INTEGER NOT NULL, compliance INTEGER NOT NULL, created_at TEXT NOT NULL);

CREATE TABLE uploaded_files (id INTEGER PRIMARY KEY AUTOINCREMENT, user_id INTEGER NOT NULL REFERENCES users(id), original_name TEXT NOT NULL, saved_name TEXT NOT NULL, file_size INTEGER NOT NULL, uploaded_at TEXT NOT NULL, attempt_id INTEGER REFERENCES attempts(id), step_id INTEGER REFERENCES scenario_steps(id), purpose TEXT NOT NULL DEFAULT 'general');

CREATE TABLE users (id INTEGER PRIMARY KEY AUTOINCREMENT, username TEXT UNIQUE NOT NULL, password_hash TEXT NOT NULL, full_name TEXT NOT NULL, email TEXT NOT NULL, role_id INTEGER NOT NULL REFERENCES roles(id), created_at TEXT NOT NULL, is_active INTEGER NOT NULL DEFAULT 1);